    array('title' => 'Heredity and Race-Improvement', 'author' => '', 'year' => '', 'category' => 'Work songs', 'lyrics' => "\"Yet are thy skies as blue, thy crags as wild;
Sweet are thy groves, and verdant are thy fields,
Thine olive ripe as when Minerva smiled,
