    array('title' => 'The Life of Captain Matthew Flinders, R.N.', 'author' => '', 'year' => '', 'category' => 'Sea songs', 'lyrics' => "PROFESSOR OF HISTORY IN THE UNIVERSITY OF MELBOURNE

