    array('title' => 'Kaele[137] wale Hilo i ke alai ia e ka ua.', 'author' => 'Emerson, Nathaniel Bright', 'year' => '', 'category' => 'Drinking songs', 'lyrics' => "Oi ka niho o ka ua o Hilo i ka lani;
