    array('title' => 'Pili-kau[142] mai Hilo ia ua loa.', 'author' => 'Emerson, Nathaniel Bright', 'year' => '', 'category' => 'Drinking songs', 'lyrics' => "20   Pali-ku laau ka uka o Haili[143]
