    array('title' => 'An arched roof the peak’s crest Hale-hale-o-ú.', 'author' => 'Emerson, Nathaniel Bright', 'year' => '', 'category' => 'Hymns', 'lyrics' => "A twisted cord hangs the brook Wai-hilau;
