    array('title' => 'O kolohe, o alai mai ka Unu-lau.', 'author' => 'Emerson, Nathaniel Bright', 'year' => '', 'category' => 'Folk songs', 'lyrics' => "Puni’a iluna o ka Halau-a-ola;
