    array('title' => 'The watch-bird, that fends off the rain from Le-hu-a—', 'author' => 'Emerson, Nathaniel Bright', 'year' => '', 'category' => 'Sea songs', 'lyrics' => "5   Shrieks, “Light not on terrace of Lei-no-ai,
