    array('title' => 'Flows from the lips, of gratitude and love.', 'author' => 'Hayley, William', 'year' => '', 'category' => 'Love songs', 'lyrics' => "Cowper still lives, to truth's clear optics given,
Endear'd to earth, and recompens'd by heaven!
And O dear lady! who like him, canst feel
