    array('title' => 'Would rob the Saviour of his rights divine.', 'author' => 'Hayley, William', 'year' => '', 'category' => 'Hymns', 'lyrics' => "There are, who call Him, by their dreams beguil'd,
Mere man; of mortal geniture the child!
