    array('title' => 'Falls prostrate, wither\'d, languid, and forlorn.', 'author' => 'Wheatley, Phillis', 'year' => '', 'category' => 'Folk songs', 'lyrics' => "\"Where flies my James?\" 'tis thus I seem to hear
