    array('title' => 'Of the little children of the fold.', 'author' => 'Ryan, Abram Joseph', 'year' => '', 'category' => 'Children\'s songs', 'lyrics' => "The old forgot they were not young,
The young forgot they would e'er be old,
And all day long the trees among,
Where'er their footsteps stayed or strolled,
Came wittiest word from tireless tongue,
And the merriest peals of laughter rung", 'source_url' => 'https://gutendex.com/books/937'),
    array('title' => 'Where the woods drooped low and the river rolled.', 'author' => 'Ryan, Abram Joseph', 'year' => '', 'category' => 'Folk songs', 'lyrics' => "No cloud upon the faces there,
Not a sorrow came from its hiding place
To cast the shadow of a care
